`renderer.js`
import * as THREE from 'three'; /** @returns {THREE.WebGLRenderer} */
export function createRenderer() { const r = new THREE.WebGLRenderer({ antialias: true }); r.setPixelRatio(Math.min(window.devicePixelRatio, 2)); return r;
}
`camerman.js`
import * as THREE from 'three'; /** @returns {THREE.PerspectiveCamera} */
export function createCamera() { return new THREE.PerspectiveCamera(60, 1, 0.1, 100);
}
